import{_ as c}from"./plugin-vue_export-helper-c27b6911.js";import{r as n,o as s,c as i,e as u,a as e,b as o,d as t,f as d}from"./app-2bd9cfaa.js";const r={},p=e("p",null,"生命周期组件，所有的生命周期函数都由这个组件实现",-1),_=d(`<h2 id="组件特性" tabindex="-1"><a class="header-anchor" href="#组件特性" aria-hidden="true">#</a> 组件特性</h2><ul><li>自动执行父类生命周期函数</li></ul><blockquote><p>所有的生命周期函数onLoad、start、create、init、open...等等，都会先执行父类的函数，再执行子类的函数，不必你手动调用 <code>super.xxx()</code>。</p></blockquote><ul><li>函数阻塞警告</li></ul><blockquote><p>DEBUG 模式时启用，当 create, init, open, close, late_close 函数阻塞时，会打印阻塞错误，阻塞时间配置为 <code>global_config.view.blocking_warning_time_ms_n</code></p></blockquote><ul><li>关闭模块自动重置数据</li></ul><blockquote><p>当模块 close 完毕后且 <code>this.data</code> 为一个 class 类型数据，组件会自动将 <code>this.data</code> 赋值为 <code>new class</code> 的数据</p></blockquote><ul><li>自动清理事件/数据事件</li></ul><blockquote><p>如果你的事件对象为 <code>mk.event_target</code>、<code>mk.monitor</code> 类型且监听时填写事件目标，如下</p><div class="language-typescript line-numbers-mode" data-ext="ts"><pre class="language-typescript"><code><span class="token comment">// 第三个参数为事件对象</span>
main_bundle<span class="token punctuation">.</span>event<span class="token punctuation">.</span><span class="token function">on</span><span class="token punctuation">(</span>main_bundle<span class="token punctuation">.</span>event<span class="token punctuation">.</span>key<span class="token punctuation">.</span>template<span class="token punctuation">,</span> <span class="token keyword">this</span><span class="token punctuation">.</span>_event_template<span class="token punctuation">,</span> <span class="token keyword">this</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>那么事件会在组件 close 后释放，避免写一堆冗余的事件注销代码<br><br> 如果你的事件对象不是以上所说类型但是包含 <code>targetOff</code> 或 <code>target_off</code> 函数，你也可以使用 <code>this.event_target_as.push(event_target)</code> 自动跟随组件释放</p></blockquote><ul><li>跟随模块释放资源</li></ul><blockquote><p><code>this.follow_release(...)</code> 传入跟随释放资源，<code>this.cancel_release(...)</code> 取消跟随释放资源<br><br> 参数类型支持 <code>cc.Node | cc.Asset | mk.audio_._unit | 函数 | 对象</code>，详情查看 <code>mk.release_.release_param_type</code></p></blockquote><ul><li>独立日志打印</li></ul><blockquote><p>可用 <code>this._log.log</code>、<code>this._log.warn</code>、<code>this._log.error</code> 打印模块专属日志</p></blockquote><ul><li>自动清理定时器</li></ul><blockquote><p>在模块 close 后，将自动执行 <code>this.unscheduleAllCallbacks()</code> 清理定时器</p></blockquote><h2 id="生命周期函数" tabindex="-1"><a class="header-anchor" href="#生命周期函数" aria-hidden="true">#</a> 生命周期函数</h2>`,16),k={href:"https://muzzik.gitee.io/mk-framework/quick-start/3.html#%E7%94%9F%E5%91%BD%E5%91%A8%E6%9C%9F",target:"_blank",rel:"noopener noreferrer"},h=e("ul",null,[e("li",null,[e("p",null,"create")]),e("li",null,[e("p",null,"init")]),e("li",null,[e("p",null,"open")]),e("li",null,[e("p",null,"close")])],-1),m=e("hr",null,null,-1),b=e("h3",null,"📣 觉得很赞？分享给你的朋友吧！",-1);function f(g,v){const l=n("ExternalLinkIcon"),a=n("Share");return s(),i("div",null,[p,u(" more "),_,e("p",null,[o("由于"),e("a",k,[o("快速开始"),t(l)]),o("已经介绍过，这里不过多赘述")]),h,m,b,t(a,{services:"qq,qrcode",colorful:""})])}const w=c(r,[["render",f],["__file","2.html.vue"]]);export{w as default};
